#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    int target; cin >> target;
    int left = 0, right = n;
    while(left < right) {
        int mid = left + (right - left) / 2;
        if(nums[mid] <= target) left = mid + 1;
        else right = mid;
    }
    cout << left;
}
